  icon: string;
}

export interface Message {
  role: 'user' | 'model';
  text: string;
}

import { GoogleGenAI } from "@google/genai";

const SYSTEM_INSTRUCTION = `
Eres el Consultor Inteligente de Grupo-AR, una empresa líder en construcción, arquitectura e ingeniería industrial. 
Tu objetivo es ayudar a los clientes potenciales a entender cómo Grupo-AR puede realizar sus proyectos.

Información clave de Grupo-AR:
- Servicios: Diseño arquitectónico, Construcción civil, Mantenimiento industrial, Estructuras metálicas, Ingeniería de detalle.
- Valores: Calidad, Innovación, Seguridad y Cumplimiento de plazos.

Cuando un usuario pregunte por un presupuesto, dales una estimación general basada en estándares del mercado (aclarando que es solo una referencia) y anímalos a contactar directamente al equipo humano.
Responde de manera profesional, técnica pero accesible, y siempre en español.
`;

export async function chatWithGemini(userMessage: string, history: { role: 'user' | 'model', parts: { text: string }[] }[]) {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [
        ...history,
        { role: 'user', parts: [{ text: userMessage }] }
      ],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.7,
      },
    });

    return response.text || "Lo siento, tuve un problema procesando tu solicitud. Por favor contacta a soporte.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "En este momento no puedo responder. Por favor, intenta más tarde o usa nuestro formulario de contacto.";
  }
}

import React, { useState, useEffect } from 'react';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import Services from './components/Services';
import Portfolio from './components/Portfolio';
import Stats from './components/Stats';
import ChatBot from './components/ChatBot';
import Contact from './components/Contact';
import Footer from './components/Footer';

const App: React.FC = () => {
  const [isScrolled, setIsScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 50);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <div className="min-h-screen flex flex-col">
      <Navbar isScrolled={isScrolled} />

      <main className="flex-grow">
        <section id="inicio">
          <Hero />
        </section>

        <section id="servicios" className="py-20 bg-white">
          <Services />
        </section>

        <section id="proyectos" className="py-20 bg-slate-50">
          <Portfolio />
        </section>

        <Stats />

        <section id="contacto" className="py-20 bg-white">
          <Contact />
        </section>
      </main>

      <ChatBot />
      <Footer />
    </div>
  );
};

export default App;

